152	func (s *Service) GetActiveContractForService(ctx context.Context, serviceID string) (*models.Contract, error) {
153		if serviceID == "" {
154			return nil, fmt.Errorf("service_id is required: %w", terrors.ErrBadRequest)
155		}
156	
157		contract, err := s.store.GetActiveContractForService(ctx, serviceID)
158		if err != nil {
159			if errors.Is(err, terrors.ErrNotFound) {
160				return nil, fmt.Errorf("no active contract found for service: %w", terrors.ErrNotFound)
161			}
162			return nil, fmt.Errorf("failed to get active contract: %w", err)
163		}
164	
165		return contract, nil
166	}
