297	// EligibilityCallbackSuccess handles the callback from the eligibility provider once the
298	// eligibility check has completed. The outcome.Decision field determines the result.
299	func (s *Service) EligibilityCallbackSuccess(ctx context.Context, requestID string, outcome models.EligibilityOutcome) error {
300		if requestID == "" {
301			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
302		}
303	
304		contract, err := s.store.GetContractByRequestID(ctx, requestID)
305		if err != nil {
306			return fmt.Errorf("failed to get contract: %w", err)
307		}
308	
309		// Only the first eligibility callback should move a contract out of pending.
310		if contract.Status != models.ContractStatusPendingEligibility {
311			return nil
312		}
313	
314		if err := s.store.UpdateContractEligibilityApproved(ctx, requestID, outcome); err != nil {
315			return fmt.Errorf("failed to update contract status: %w", err)
316		}
317	
318		if err := s.eventProducer.ProduceMobileHandsetContractApprovedSync(ctx, &serviceevents.MobileHandsetContractApproved{
319			ServiceId:      contract.ServiceID,
320			CustomerId:     contract.CustomerID,
321			ContractId:     contract.ID,
322			HandsetId:      contract.HandsetID,
323			HandsetName:    contract.HandsetName,
324			ContractPrice:  money(contract.ContractPricePence),
325			RetailPrice:    money(contract.RetailPricePence),
326			ContractMonths: contract.ContractMonths,
327		}); err != nil {
328			tlog.WithError(err).
329				WithAttribute("contract_id", contract.ID).
330				Error(ctx, "failed to produce MobileHandsetContractApproved event")
331		}
332	
333		tlog.WithAttribute("request_id", requestID).
334			WithAttribute("contract_id", contract.ID).
335			WithAttribute("decision", outcome.Decision).
336			Info(ctx, "eligibility approved, contract awaiting loan processing")
337	
338		return nil
339	}
