341	func (s *Service) releaseHandsetStock(ctx context.Context, handsetID string) {
342		if err := s.store.DecrementHandsetOrdersPlaced(ctx, handsetID); err != nil {
343			tlog.WithError(err).
344				WithAttribute("handset_id", handsetID).
345				Error(ctx, "failed to release reserved handset stock")
346		}
347	}
